// A prepared Playwright check that is FAILING on purpose.
//
// This lab is about READING a failure, not fixing it. Run this test, read
// what it prints, and copy four facts into EVIDENCE.md:
//
//   1. Test      — the name of the test that failed
//   2. Location  — the file and line the result points to for the failed check
//   3. Expected  — the text the test expected to see
//   4. Received  — the text the page actually showed
//
// DO NOT edit this file or the page. The failure is the lesson.
import { test, expect } from "@playwright/test";

// The page is a plain HTML file — the test opens it straight from disk.
const appUrl = new URL("../app/index.html", import.meta.url).href;

test.beforeEach(async ({ page }) => {
  await page.goto(appUrl);
});

test("garden status banner", async ({ page }) => {
  await expect(page.getByTestId("plot-status")).toHaveText("Plot requests are closed");
});
